options.afterRender:
// ╔══════════════════════════════════════════════════════════════════════╗
// ║  BPC NOC — HEADER GLOBAL                                            ║
// ║                                                                      ║
// ║  Carregado UMA única vez, no painel de cabeçalho.                   ║
// ║  Tudo o que é partilhado entre painéis vive aqui.                   ║
// ║                                                                      ║
// ║  BLOCO 1 — Bootstrap do namespace + CSS global + Utils + RPC        ║
// ║  BLOCO 2 — Render do cabeçalho NOC                                  ║
// ║                                                                      ║
// ║  Regras para os painéis dependentes:                                ║
// ║    • Nunca repetir CSS .bpc-* — vive exclusivamente aqui            ║
// ║    • Nunca redefinir utils ou rpc — usar window.BPC.*               ║
// ║    • Usar sempre window.waitForBPC(cb) como ponto de entrada        ║
// ║    • O callback recebe rpc como argumento: waitForBPC(rpc => {...}) ║
// ║    • Nunca chamar window.BPC.rpc(...) diretamente nos cards         ║
// ║                                                                      ║
// ║  O que NÃO pertence aqui:                                           ║
// ║    • Lógica específica de cada painel/camada                        ║
// ║    • Queries específicas (MSSQL, Oracle, SNMP…)                     ║
// ║    • HTML de cards de detalhe                                       ║
// ╚══════════════════════════════════════════════════════════════════════╝


// ════════════════════════════════════════════════════════════════════════
//  BLOCO 1 — BOOTSTRAP: NAMESPACE · CSS GLOBAL · UTILS · RPC
//
//  Sequência interna estrita:
//    1. Namespace window.BPC
//    2. BPC.log (disponível o mais cedo possível)
//    3. CSS global (injectado uma vez)
//    4. window.waitForBPC (disponível imediatamente para os painéis)
//       → O callback recebe (rpc) como argumento — contrato ChatGPT
//    5. window.BPC.utils (síncrono — sem polling)
//    6. RPC (fetch) → chama BPC.setReady(rpcFn) → desbloqueia callbacks
//
//  Quando setReady() é chamado, utils e log já estão completos.
//  Não há race condition entre utils, log e rpc.
// ════════════════════════════════════════════════════════════════════════

(function bootstrap() {

  // ── 1. Guard de re-inicialização ────────────────────────────────────

  const VERSION = 'v5';  // ← bump em relação ao v4 anterior

  if (window.BPC && window.BPC.version === VERSION) {
    const cssOk = !!document.getElementById('bpc-global-css');
    const utilsOk = typeof (window.BPC.utils && window.BPC.utils.waitForElement) === 'function';
    const rpcOk = typeof window.BPC.rpc === 'function';
    const logOk = typeof window.BPC.log === 'function';

    if (cssOk && utilsOk && rpcOk && logOk) return;

    console.warn('[BPC] Estado parcial detectado — reinicializando (' + VERSION + ')');
    window.BPC._ready = false;
    window.BPC.rpc = null;
    // _callbacks preservado: painéis em espera recebem o novo rpc
  }


  // ── 2. Namespace ─────────────────────────────────────────────────────

  window.BPC = window.BPC || {};
  Object.assign(window.BPC, {
    version: VERSION,
    rpc: null,
    _ready: false,
    _callbacks: window.BPC._callbacks || [],

    onReady(cb) {
      if (this._ready && typeof this.rpc === 'function') {
        try { cb(this.rpc); } catch (e) { console.error('[BPC] onReady callback:', e); }
      } else {
        this._callbacks.push(cb);
      }
    },

    setReady(rpcFn) {
      this.rpc = rpcFn;
      this._ready = true;
      BPC.log('Runtime pronto (rpc, utils, log disponíveis)');
      const pending = this._callbacks.splice(0);
      pending.forEach(cb => {
        try { cb(rpcFn); } catch (e) { console.error('[BPC] setReady callback:', e); }
      });
    },
  });


  // ── 3. BPC.log ───────────────────────────────────────────────────────
  // Logging centralizado — prefixo [BPC] em todas as mensagens.
  // Disponível antes de utils e rpc para poder ser usado em qualquer
  // fase do bootstrap.
  //
  // Níveis: log (info), warn, error
  // Uso:
  //   BPC.log('Card carregado');
  //   BPC.log('Aviso', 'warn');
  //   BPC.log('Erro fatal', 'error');

  window.BPC.log = function (msg, level) {
    const prefix = '[BPC]';
    if (level === 'error') {
      console.error(prefix, msg);
    } else if (level === 'warn') {
      console.warn(prefix, msg);
    } else {
      console.log(prefix, msg);
    }
  };

  const BPC = window.BPC;  // atalho local para o resto do bootstrap


  // ── 4. CSS Global ────────────────────────────────────────────────────

  if (!document.getElementById('bpc-global-css')) {
    const style = document.createElement('style');
    style.id = 'bpc-global-css';
    style.textContent = `

      /* ── Base ──────────────────────────────────────────────────────── */
      .bpc { font-family: 'Segoe UI', 'Inter', sans-serif; box-sizing: border-box; }

      /* ── Glass Card ────────────────────────────────────────────────── */
      .bpc-card {
        background: rgba(255,255,255,0.04);
        border: 1px solid rgba(255,255,255,0.09);
        border-radius: 12px;
        padding: 14px 16px;
        backdrop-filter: blur(12px);
        -webkit-backdrop-filter: blur(12px);
        position: relative;
        overflow: hidden;
        transition: border-color .2s;
      }
      .bpc-card::before {
        content: '';
        position: absolute; top: 0; left: 0; right: 0; height: 1px;
        background: linear-gradient(90deg, transparent, rgba(255,255,255,0.22), transparent);
      }
      .bpc-card:hover { border-color: rgba(255,255,255,0.18); }

      /* ── Layout ────────────────────────────────────────────────────── */
      .bpc-flex     { display: flex; align-items: center; }
      .bpc-flex-col { display: flex; flex-direction: column; }
      .bpc-gap-4    { gap: 4px; }
      .bpc-gap-8    { gap: 8px; }
      .bpc-gap-12   { gap: 12px; }

      /* ── Tipografia ────────────────────────────────────────────────── */
      .bpc-label    { font-size: 0.70rem; font-weight: 600; letter-spacing: .06em; text-transform: uppercase; color: #8B949E; }
      .bpc-value-lg { font-size: 1.8rem;  font-weight: 700; color: #E6EDF3; line-height: 1; }
      .bpc-value-md { font-size: 1.1rem;  font-weight: 600; color: #E6EDF3; line-height: 1; }
      .bpc-value-sm { font-size: 0.85rem; font-weight: 600; color: #E6EDF3; line-height: 1; }

      /* ── Cores de estado ───────────────────────────────────────────── */
      .bpc-ok   { color: #3FB950; }
      .bpc-warn { color: #D29922; }
      .bpc-crit { color: #F85149; }
      .bpc-info { color: #58A6FF; }
      .bpc-mute { color: #8B949E; }

      /* ── Pill Badges ───────────────────────────────────────────────── */
      .bpc-pill {
        font-size: 0.65rem; font-weight: 700; letter-spacing: .08em;
        text-transform: uppercase; padding: 2px 8px;
        border-radius: 12px; border: 1px solid transparent; white-space: nowrap;
      }
      .bpc-pill.ok   { background: rgba(63,185,80,0.08);  color: #3FB950; border-color: #238636; }
      .bpc-pill.warn { background: rgba(210,153,34,0.08); color: #D29922; border-color: #9E6A03; }
      .bpc-pill.down {
        background: rgba(248,81,73,0.08); color: #F85149; border-color: #6E1A1A;
        animation: bpc-pulse 1.2s ease-in-out infinite;
      }

      /* ── Animações ─────────────────────────────────────────────────── */
      @keyframes bpc-pulse {
        0%, 100% { box-shadow: 0 0 0 0   rgba(248,81,73,0.45); }
        50%       { box-shadow: 0 0 0 5px rgba(248,81,73,0); }
      }
      @keyframes bpc-card-down {
        0%, 100% { background: rgba(248,81,73,0.04); box-shadow: 0 0 0 0 rgba(248,81,73,0.3); }
        50%       { background: rgba(248,81,73,0.09); box-shadow: 0 0 18px 4px rgba(248,81,73,0.12); }
      }
      @keyframes bpc-card-warn {
        0%, 100% { background: rgba(255,255,255,0.04); }
        50%       { background: rgba(210,153,34,0.07); }
      }
      @keyframes bpc-shimmer {
        0%   { background-position: 200% 0; }
        100% { background-position: -200% 0; }
      }

      /* ── Estado visual do card ─────────────────────────────────────── */
      .bpc-card.state-warn { animation: bpc-card-warn 3s ease-in-out infinite; }
      .bpc-card.state-down { border-color: rgba(248,81,73,0.25); animation: bpc-card-down 2s ease-in-out infinite; }

      /* ── Skeleton Loader ───────────────────────────────────────────── */
      .bpc-skeleton {
        background: linear-gradient(90deg,
          rgba(255,255,255,0.05) 25%,
          rgba(255,255,255,0.10) 50%,
          rgba(255,255,255,0.05) 75%);
        background-size: 200% 100%;
        animation: bpc-shimmer 1.4s infinite;
        border-radius: 4px;
      }

      /* ── Elementos auxiliares ──────────────────────────────────────── */
      .bpc-divider   { width: 1px; align-self: stretch; flex-shrink: 0; background: rgba(255,255,255,0.07); }
      .bpc-timestamp { font-size: 0.60rem; color: rgba(255,255,255,0.18); text-align: right; margin-top: 4px; }

    `;
    document.head.appendChild(style);
    BPC.log('CSS global injectado');
  }


  // ── 5. window.waitForBPC ─────────────────────────────────────────────
  // Ponto de entrada obrigatório para TODOS os painéis.
  //
  // ┌─ CONTRATO (alinhado com ChatGPT) ──────────────────────────────┐
  // │  O callback recebe (rpc) como argumento:                       │
  // │    window.waitForBPC(function(rpc) { ... })                    │
  // │                                                                │
  // │  Equivalente a escrever nos cards:                             │
  // │    window.waitForBPC(rpc => {                                  │
  // │      BPC.utils.waitForElement('bpc-card-x', el => {           │
  // │        function load() { rpc('host.get', {...}) }              │
  // │        load();                                                  │
  // │        BPC.utils.startRefresh(el, load, 60000);               │
  // │      });                                                       │
  // │    });                                                         │
  // └────────────────────────────────────────────────────────────────┘
  //
  // Guard de versão: evita sobrescrever em hot-reload se já estiver
  // correto — mas substitui se a versão diferir.

  if (typeof window.waitForBPC !== 'function' || window.waitForBPC._bpcVersion !== VERSION) {
    window.waitForBPC = function (cb) {
      const t0 = Date.now();
      const timeout = 15000;

      const poll = setInterval(() => {
        // Condição completa: BPC pronto + rpc function + utils completo
        if (
          window.BPC &&
          window.BPC._ready &&
          typeof window.BPC.rpc === 'function' &&
          window.BPC.utils &&
          typeof window.BPC.utils.waitForElement === 'function' &&
          typeof window.BPC.log === 'function'
        ) {
          clearInterval(poll);
          try {
            // ← MUDANÇA PRINCIPAL: passa rpc ao callback (contrato ChatGPT)
            cb(window.BPC.rpc);
          } catch (e) {
            console.error('[BPC] waitForBPC callback:', e);
          }
          return;
        }

        if (Date.now() - t0 > timeout) {
          clearInterval(poll);
          console.error('[BPC] waitForBPC: timeout após 15s — header-global.js não inicializou.');
          document.querySelectorAll('[id^="bpc-card-"]').forEach(el => {
            if (!el.innerHTML.trim()) {
              el.innerHTML = '<div style="color:#F85149;padding:12px;font-size:.75rem">⚠ Header não inicializou</div>';
            }
          });
        }
      }, 30);
    };
    window.waitForBPC._bpcVersion = VERSION;
    BPC.log('waitForBPC registado (versão ' + VERSION + ')');
  }


  // ── 6. BPC.utils ─────────────────────────────────────────────────────
  // Inicializado SINCRONAMENTE — sem polling, sem setTimeout.

  window.BPC.utils = {

    // ── DOM ──────────────────────────────────────────────────────────────

    /**
     * Aguarda um elemento DOM estar disponível e chama o callback.
     * Uso: BPC.utils.waitForElement('meu-id', el => { ... })
     */
    waitForElement(id, cb, timeoutMs) {
      const t0 = Date.now();
      const poll = setInterval(() => {
        const el = document.getElementById(id);
        if (el) { clearInterval(poll); cb(el); return; }
        if (Date.now() - t0 > (timeoutMs || 10000)) {
          clearInterval(poll);
          BPC.log('waitForElement: timeout para #' + id, 'warn');
        }
      }, 50);
    },

    /**
     * Inicia (ou reinicia) um intervalo de refresh ligado a um elemento DOM.
     * Guarda o timer em el._bpcTimer — limpa o anterior se existir.
     * Uso: BPC.utils.startRefresh(el, () => carregarDados(), 60000)
     */
    startRefresh(el, fn, intervalMs) {
      if (el._bpcTimer) clearInterval(el._bpcTimer);
      el._bpcTimer = setInterval(fn, intervalMs);
    },


    // ── ESTADO ────────────────────────────────────────────────────────────

    stateClass(state) {
      return { ok: 'bpc-ok', warn: 'bpc-warn', down: 'bpc-crit' }[state] || 'bpc-mute';
    },

    stateLabel(state) {
      return { ok: 'OK', warn: 'DEGRADADO', down: 'DOWN' }[state] || '—';
    },

    stateAbove(value, thr) {
      if (value == null || isNaN(value)) return 'mute';
      if (value >= thr.crit) return 'down';
      if (value >= thr.warn) return 'warn';
      return 'ok';
    },

    stateBelow(value, thr) {
      if (value == null || isNaN(value)) return 'mute';
      if (value <= thr.crit) return 'down';
      if (value <= thr.warn) return 'warn';
      return 'ok';
    },


    // ── FORMATAÇÃO ────────────────────────────────────────────────────────

    fmtBytes(bytes) {
      if (bytes == null || isNaN(bytes) || bytes < 0) return '—';
      if (bytes >= 1e12) return (bytes / 1e12).toFixed(2) + ' TB';
      if (bytes >= 1e9) return (bytes / 1e9).toFixed(1) + ' GB';
      if (bytes >= 1e6) return (bytes / 1e6).toFixed(1) + ' MB';
      if (bytes >= 1e3) return (bytes / 1e3).toFixed(0) + ' KB';
      return bytes + ' B';
    },

    fmtMb(mb) {
      if (mb == null || isNaN(mb) || mb < 0) return '—';
      if (mb >= 1024 * 1024) return (mb / 1024 / 1024).toFixed(2) + ' TB';
      if (mb >= 1024) return (mb / 1024).toFixed(1) + ' GB';
      return mb + ' MB';
    },

    fmtMs(ms) {
      if (ms == null || isNaN(ms) || ms < 0) return '—';
      if (ms >= 1000) return (ms / 1000).toFixed(2) + ' s';
      return ms.toFixed(2) + ' ms';
    },

    fmtPct(value, decimals) {
      if (value == null || isNaN(value)) return '—';
      return value.toFixed(decimals ?? 1) + '%';
    },

    fmtTime(unixSec) {
      if (!unixSec) return '—';
      return new Date(unixSec * 1000).toLocaleTimeString('pt-PT');
    },


    // ── QUERIES GENÉRICAS ─────────────────────────────────────────────────

    /**
     * Query ICMP genérica para cards KPI de camada.
     * Uso: const d = await BPC.utils.fetchICMP(rpc, '136', { rttWarnMs: 5, lossWarnPct: 5 })
     */
    async fetchICMP(rpc, groupid, thr) {
      const rttWarn = (thr && thr.rttWarnMs) || 5;
      const lossWarn = (thr && thr.lossWarnPct) || 5;

      BPC.log('fetchICMP → groupid=' + groupid);

      const allItems = await rpc('item.get', {
        groupids: [groupid],
        search: { key_: 'icmpping' },
        filter: { status: 0 },
        output: ['hostid', 'key_', 'lastvalue', 'itemid'],
      });

      const byHost = {};
      allItems.forEach(i => {
        if (!byHost[i.hostid]) byHost[i.hostid] = { up: null, rtt: 0, loss: 0, rttItemId: null };
        const h = byHost[i.hostid];
        if (i.key_ === 'icmpping') h.up = i.lastvalue === '1';
        if (i.key_.startsWith('icmppingsec')) { h.rtt = parseFloat(i.lastvalue) * 1000; h.rttItemId = i.itemid; }
        if (i.key_.startsWith('icmppingloss')) { h.loss = parseFloat(i.lastvalue); }
      });

      const hostIds = Object.keys(byHost);
      const total = hostIds.length;
      if (!total) return { total: 0, down: 0, warn: 0, ok: 0, rtt: 0, loss: 0, sparkData: [] };

      const downSet = new Set();
      const warnSet = new Set();

      hostIds.forEach(id => {
        const h = byHost[id];
        if (h.up === false || h.up === null) {
          downSet.add(id);
        } else if (h.rtt > rttWarn || h.loss > lossWarn) {
          warnSet.add(id);
        }
      });

      const upIds = hostIds.filter(id => !downSet.has(id));
      const avg = arr => arr.length ? arr.reduce((a, b) => a + b, 0) / arr.length : 0;
      const avgRtt = avg(upIds.map(id => byHost[id].rtt).filter(v => v > 0));
      const avgLoss = avg(upIds.map(id => byHost[id].loss).filter(v => v > 0));

      let sparkData = [];
      const firstUp = upIds.find(id => byHost[id].rttItemId);
      if (firstUp) {
        const now = Math.floor(Date.now() / 1000);
        const hist = await rpc('history.get', {
          itemids: [byHost[firstUp].rttItemId],
          time_from: now - 3600,
          time_till: now,
          output: 'extend',
          sortfield: 'clock',
          sortorder: 'ASC',
          limit: 30,
        });
        sparkData = hist.map(h => parseFloat(h.value) * 1000);
      }

      BPC.log('fetchICMP ← total=' + total + ' down=' + downSet.size + ' warn=' + warnSet.size);

      return {
        total,
        down: downSet.size,
        warn: warnSet.size,
        ok: Math.max(0, total - downSet.size - warnSet.size),
        rtt: avgRtt,
        loss: avgLoss,
        sparkData,
      };
    },


    // ── RENDER PARTILHADO ─────────────────────────────────────────────────

    buildSparkline(data, color) {
      if (!data || data.length < 2) return '';
      const W = 140, H = 32;
      const mn = Math.min(...data);
      const mx = Math.max(...data);
      const rng = mx - mn || 1;
      const step = W / (data.length - 1);
      const pts = data.map((v, i) =>
        (i * step).toFixed(1) + ',' + (H - ((v - mn) / rng) * (H - 4) - 2).toFixed(1)
      ).join(' ');
      return '<svg width="' + W + '" height="' + H + '" viewBox="0 0 ' + W + ' ' + H + '">'
        + '<polyline points="' + pts + '" fill="none" stroke="' + color
        + '" stroke-width="1.5" stroke-linejoin="round" stroke-linecap="round" opacity="0.85"/>'
        + '</svg>';
    },

    buildLayerCard(cfg, d) {
      const u = window.BPC.utils;
      const status = d.down > 0 ? 'down' : d.warn > 0 ? 'warn' : 'ok';
      const avail = d.total > 0 ? Math.round((d.ok / d.total) * 100) : 0;
      const availClass = avail === 100 ? 'bpc-ok' : avail >= 80 ? 'bpc-warn' : 'bpc-crit';
      const spark = u.buildSparkline(d.sparkData, cfg.color);

      const rttLabel = d.down === d.total ? '—' : u.fmtMs(d.rtt);
      const lossLabel = d.down === d.total ? '—' : u.fmtPct(d.loss);
      const lossClass = d.loss > 5 ? 'bpc-warn' : 'bpc-ok';

      return '<a href="/d/' + cfg.dashUid + '" style="text-decoration:none;display:block;height:100%">'
        + '<div class="bpc bpc-card state-' + status + '" style="'
        + 'height:100%;cursor:pointer;border-top:3px solid ' + cfg.color + ';'
        + 'display:flex;flex-direction:column;gap:8px;">'

        + '<div class="bpc-flex" style="justify-content:space-between;align-items:flex-start">'
        + '<span class="bpc-label" style="color:' + cfg.color + ';font-size:.75rem">' + cfg.label + '</span>'
        + '<span class="bpc-pill ' + status + '">' + u.stateLabel(status) + '</span>'
        + '</div>'

        + '<div class="bpc-flex bpc-gap-12">'
        + '<div class="bpc-flex-col bpc-gap-4"><span class="bpc-value-lg">' + d.total + '</span><span class="bpc-label">Total</span></div>'
        + '<div class="bpc-flex-col bpc-gap-4"><span class="bpc-value-md bpc-crit">' + d.down + '</span><span class="bpc-label">Down</span></div>'
        + '<div class="bpc-flex-col bpc-gap-4"><span class="bpc-value-md bpc-warn">' + d.warn + '</span><span class="bpc-label">Degradado</span></div>'
        + '<div class="bpc-flex-col bpc-gap-4" style="margin-left:auto;text-align:right">'
        + '<span class="bpc-value-md ' + availClass + '">' + avail + '%</span>'
        + '<span class="bpc-label">Disponib.</span></div>'
        + '</div>'

        + '<div class="bpc-flex bpc-gap-12">'
        + '<div class="bpc-flex-col bpc-gap-4"><span class="bpc-value-md bpc-info">' + rttLabel + '</span><span class="bpc-label">RTT médio</span></div>'
        + '<div class="bpc-flex-col bpc-gap-4"><span class="bpc-value-md ' + lossClass + '">' + lossLabel + '</span><span class="bpc-label">Loss médio</span></div>'
        + '</div>'

        + '<div style="margin-top:auto;opacity:.85">' + spark + '</div>'

        + '</div></a>';
    },

    buildError(label, message, color) {
      return '<div class="bpc bpc-card state-down" style="height:100%;'
        + (color ? 'border-top:3px solid ' + color + ';' : '') + '">'
        + (label ? '<span class="bpc-label" style="color:' + (color || '#8B949E') + '">' + label + '</span>' : '')
        + '<div style="color:#F85149;font-size:.78rem;margin-top:8px">⚠ ' + message + '</div>'
        + '</div>';
    },

    buildSkeleton(color) {
      return '<div class="bpc bpc-card" style="height:100%;'
        + (color ? 'border-top:3px solid ' + color + ';' : '')
        + 'display:flex;flex-direction:column;gap:10px">'
        + '<div class="bpc-skeleton" style="height:12px;width:50%"></div>'
        + '<div class="bpc-skeleton" style="height:32px;width:60%"></div>'
        + '<div class="bpc-skeleton" style="height:14px;width:80%"></div>'
        + '<div class="bpc-skeleton" style="height:14px;width:40%;margin-top:auto"></div>'
        + '</div>';
    },

  }; // fim BPC.utils

  BPC.log('utils inicializado');


  // ── 7. RPC — Zabbix API via proxy Grafana ────────────────────────────
  // Alterar API_URL se o IP ou UID da datasource Grafana mudar.
  //
  // setReady() é chamado AQUI, depois de utils e log estarem completos.

  const API_URL = 'http://10.10.126.22:3000/api/datasources/uid/3_KgG43nz/resources/zabbix-api';

  const rpcFn = async function (method, params) {
    BPC.log('rpc → ' + method);
    const res = await fetch(API_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'x-grafana-org-id': '1' },
      credentials: 'include',
