  // ── SVG Gauge 180° ────────────────────────────────────────────────
  function gaugeSVG(pct, color, w, h, subLabel) {
    var U = CFG.ui
    if (pct == null || isNaN(pct)) pct = 0
    pct = Math.max(0, Math.min(100, pct))
    var cx = w / 2, cy = h - 8
    var r = Math.min(cx - 8, cy - 4)
    var sw = 8

    function polar(deg, radius) {
      var rad = (deg - 180) * Math.PI / 180
      return { x: cx + radius * Math.cos(rad), y: cy + radius * Math.sin(rad) }
    }
    function arc(s, e, rad, sw2, col, cap) {
      var p1 = polar(s, rad), p2 = polar(e, rad)
      var large = (e - s) > 180 ? 1 : 0
      return '<path d="M' + p1.x.toFixed(2) + ',' + p1.y.toFixed(2) + ' A' + rad + ',' + rad + ' 0 ' + large + ' 1 ' + p2.x.toFixed(2) + ',' + p2.y.toFixed(2) + '"'
        + ' fill="none" stroke="' + col + '" stroke-width="' + sw2 + '"' + (cap ? ' stroke-linecap="' + cap + '"' : '') + '/>'
    }
    function tick(pv, col) {
      var a = pv * 180 / 100
      var inner = polar(a, r - sw - 3), outer = polar(a, r + 3)
      return '<line x1="' + inner.x.toFixed(1) + '" y1="' + inner.y.toFixed(1) + '" x2="' + outer.x.toFixed(1) + '" y2="' + outer.y.toFixed(1) + '" stroke="' + col + '" stroke-width="1.5" opacity="0.6"/>'
    }

    var endAngle = pct * 180 / 100
    return '<svg width="' + w + '" height="' + h + '" viewBox="0 0 ' + w + ' ' + h + '" style="display:block;overflow:visible">'
      + arc(0, 180, r, sw, 'rgba(255,255,255,0.07)', 'round')
      + (endAngle > 0 ? arc(0, endAngle, r, sw, color, 'round') : '')
      + tick(75, '#D29922') + tick(90, '#F85149')
      + '<text x="' + cx + '" y="' + (cy - 2) + '" text-anchor="middle" font-family="\'Courier New\',monospace" font-size="' + U.gaugePctSize + '" font-weight="700" fill="' + color + '">' + _pct(pct) + '</text>'
      + (subLabel ? '<text x="' + cx + '" y="' + (cy + 14) + '" text-anchor="middle" font-family="\'IBM Plex Sans\',sans-serif" font-size="' + U.gaugeSubSize + '" fill="#6E7681">' + subLabel + '</text>' : '')
      + '</svg>'
  }

  // ── Donut SVG ─────────────────────────────────────────────────────
  function donutSVG(crit, warn, info, total, w) {
    var U = CFG.ui
    var cx = w / 2, cy = w / 2, r = w / 2 - 10, sw = 10
    if (!total) {
      return '<svg width="' + w + '" height="' + w + '" viewBox="0 0 ' + w + ' ' + w + '">'
        + '<circle cx="' + cx + '" cy="' + cy + '" r="' + r + '" fill="none" stroke="rgba(255,255,255,0.07)" stroke-width="' + sw + '"/>'
        + '<text x="' + cx + '" y="' + (cy + 6) + '" text-anchor="middle" font-family="\'Courier New\',monospace" font-size="' + U.donutCenterSize + '" font-weight="700" fill="#3FB950">0</text>'
        + '</svg>'
    }
    var circ = 2 * Math.PI * r, offset = 0
    var segments = [{ v: crit, c: '#F85149' }, { v: warn, c: '#D29922' }, { v: info, c: '#58A6FF' }].filter(function (s) { return s.v > 0 })
    var paths = segments.map(function (s) {
      var dash = (s.v / total) * circ, gap = circ - dash
      var p = '<circle cx="' + cx + '" cy="' + cy + '" r="' + r + '" fill="none" stroke="' + s.c + '" stroke-width="' + sw + '"'
        + ' stroke-dasharray="' + dash.toFixed(2) + ' ' + gap.toFixed(2) + '"'
        + ' stroke-dashoffset="' + (-offset).toFixed(2) + '"'
        + ' transform="rotate(-90 ' + cx + ' ' + cy + ')"/>'
      offset += dash; return p
    })
    var totalColor = crit > 0 ? '#F85149' : warn > 0 ? '#D29922' : '#3FB950'
    return '<svg width="' + w + '" height="' + w + '" viewBox="0 0 ' + w + ' ' + w + '">'
      + '<circle cx="' + cx + '" cy="' + cy + '" r="' + r + '" fill="none" stroke="rgba(255,255,255,0.06)" stroke-width="' + sw + '"/>'
      + paths.join('')
      + '<text x="' + cx + '" y="' + (cy + 7) + '" text-anchor="middle" font-family="\'Courier New\',monospace" font-size="' + U.donutCenterSize + '" font-weight="700" fill="' + totalColor + '">' + total + '</text>'
      + '</svg>'
  }

  // ── Sparkline ─────────────────────────────────────────────────────
  function sparkSVG(data, color, w, h) {
    if (!data || data.length < 2) return ''
    var mn = Math.min.apply(null, data), mx = Math.max.apply(null, data), rng = mx - mn || 1
    var pts = data.map(function (v, i) { return [(i / (data.length - 1)) * w, h - ((v - mn) / rng) * (h - 6) - 3] })
    var ln = 'M' + pts.map(function (p) { return p[0].toFixed(1) + ',' + p[1].toFixed(1) }).join('L')
    var ar = 'M' + pts[0][0] + ',' + h + 'L' + ln.slice(1) + 'L' + pts[pts.length - 1][0] + ',' + h + 'Z'
    var gid = 'sg' + Math.random().toString(36).slice(2, 7)
    return '<svg width="' + w + '" height="' + h + '" viewBox="0 0 ' + w + ' ' + h + '" style="display:block">'
      + '<defs><linearGradient id="' + gid + '" x1="0" y1="0" x2="0" y2="1">'
      + '<stop offset="0%" stop-color="' + color + '" stop-opacity="0.2"/>'
      + '<stop offset="100%" stop-color="' + color + '" stop-opacity="0"/>'
      + '</linearGradient></defs>'
      + '<path d="' + ar + '" fill="url(#' + gid + ')" />'
      + '<path d="' + ln + '" fill="none" stroke="' + color + '" stroke-width="1.5" stroke-linejoin="round"/>'
      + '<circle cx="' + pts[pts.length - 1][0] + '" cy="' + pts[pts.length - 1][1] + '" r="2.5" fill="' + color + '"/>'
      + '</svg>'
  }

  // ── render ────────────────────────────────────────────────────────
  function render(d, isDemo, errMsg) {
    var U = CFG.ui
    var C = { ok: '#3FB950', warn: '#D29922', crit: '#F85149', info: '#58A6FF', mute: '#6E7681' }
    function sc(s) { return s === 'crit' || s === 'down' ? C.crit : s === 'warn' ? C.warn : s === 'ok' ? C.ok : C.mute }
    function rgb(h) { return parseInt(h.slice(1, 3), 16) + ',' + parseInt(h.slice(3, 5), 16) + ',' + parseInt(h.slice(5, 7), 16) }

    function badge(text, color) {
      return '<span style="font-size:' + U.badgeFontSize + ';font-weight:600;letter-spacing:.07em;text-transform:uppercase;'
        + 'padding:' + U.badgePadding + ';border-radius:3px;border:1px solid rgba(' + rgb(color) + ',.28);'
        + 'background:rgba(' + rgb(color) + ',.13);color:' + color + '">' + _esc(text) + '</span>'
    }
    function lbl(text) {
      return '<div style="font-size:' + U.labelFontSize + ';letter-spacing:' + U.labelLetterSpacing + ';color:#6E7681;font-weight:500;text-transform:uppercase;margin-bottom:6px;">' + _esc(text) + '</div>'
