      return '<a href="' + _esc(url) + '" target="_blank" '
        + 'style="display:inline-block;font-size:' + U.drillFontSize + ';color:#58A6FF;text-decoration:none;'
        + 'padding:3px 9px;border-radius:3px;border:1px solid rgba(88,166,255,0.25);background:rgba(88,166,255,0.07);'
        + 'letter-spacing:.04em;white-space:nowrap;">' + _esc(label) + ' →</a>'
