        + '</div>'
    }

    var gsCol = sc(d.globalState)
    var gsLabel = d.globalState === 'crit' ? 'CRÍTICO' : d.globalState === 'warn' ? 'DEGRADADO' : 'OK'
    var demoBar = isDemo
      ? '<div style="padding:2px 12px;background:#D2992211;border-bottom:1px solid #D2992233;font-size:' + U.demoBarSize + ';color:#D29922;letter-spacing:.08em;">⚠ DEMO' + (errMsg ? ' — ' + _esc(errMsg) : '') + ' </div>'
      : ''
    var statePill = '<div style="padding:4px 14px;border-bottom:1px solid rgba(255,255,255,0.06);display:flex;justify-content:flex-end;">'
      + '<span style="font-size:' + U.statePillSize + ';font-weight:700;padding:2px 10px;border-radius:3px;letter-spacing:.08em;'
      + 'background:rgba(' + rgb(gsCol) + ',.15);color:' + gsCol + ';border:1px solid rgba(' + rgb(gsCol) + ',.3);">'
      + gsLabel + '</span></div>'

    // ── Card 1 — Hosts ─────────────────────────────────────────────
    var hostColor = d.hostsDown > 0 ? C.warn : C.ok
    var c1 = card(hostColor, 'Hosts activos',
      '<div style="font-family:\'Courier New\',monospace;font-size:' + U.valueFontSize + ';font-weight:700;color:' + hostColor + ';line-height:1;margin-bottom:3px;">'
      + d.hostsOnline + '<span style="font-size:' + U.valueSuffixSize + ';color:#6E7681;font-weight:400;">&#8202;/&#8202;' + d.hostsTotal + '</span></div>'
      + sub(d.hostsDown > 0
        ? '<span style="color:' + C.warn + ';">● ' + d.hostsDown + ' offline' + (d.hostsDownNames && d.hostsDownNames.length ? ' · <span style="font-family:monospace;font-size:' + U.subFontSize + ';">' + d.hostsDownNames.slice(0, 2).map(_esc).join(', ') + (d.hostsDownNames.length > 2 ? ' +' + (d.hostsDownNames.length - 2) : '') + '</span>' : '') + '</span>'
        : '<span style="color:' + C.ok + ';">● todos disponíveis</span>')
