        ? '<div style="margin-top:5px;font-size:' + U.subFontSize + ';color:' + C.warn + ';font-family:monospace;">' + _esc(d.rebootHosts.slice(0, 3).join(', ') + (d.rebootHosts.length > 3 ? ' +' + (d.rebootHosts.length - 3) : '')) + '</div>'
