          + '<span style="display:inline-block;width:' + U.clusterDotSize + ';height:' + U.clusterDotSize + ';border-radius:50%;background:' + cc + ';flex-shrink:0;"></span>'
          + '<span style="font-size:' + U.clusterNameSize + ';color:' + (c.green ? '#8B949E' : C.crit) + ';white-space:nowrap;overflow:hidden;text-overflow:ellipsis;" title="' + _esc(c.name) + '">' + _esc(nm) + '</span>'
          + '</div>'
      }).join('')
      + '</div>'

    var c2 = card(clColor, 'Clusters · status',
      '<div style="font-family:\'Courier New\',monospace;font-size:' + U.valueFontSize + ';font-weight:700;color:' + clColor + ';line-height:1;margin-bottom:3px;">'
      + greenCl + '<span style="font-size:' + U.valueSuffixSize + ';color:#6E7681;font-weight:400;">&#8202;/&#8202;' + totalCl + '</span></div>'
      + sub(totalCl === 0 ? '<span style="color:#6E7681;">sem dados</span>'
        : greenCl < totalCl ? '<span style="color:' + C.crit + ';">● ' + (totalCl - greenCl) + ' cluster(s) em falha</span>'
          : '<span style="color:' + C.ok + ';">● todos healthy</span>')
      + clGrid
      + (d.vmsTotal != null
        ? '<div style="margin-top:7px;padding-top:5px;border-top:1px solid rgba(255,255,255,0.06);display:flex;align-items:center;gap:5px;">'
        + '<span style="font-family:\'Courier New\',monospace;font-size:' + U.vmCountSize + ';font-weight:700;color:#58A6FF;">' + d.vmsTotal + '</span>'
        + '<span style="font-size:' + U.vmLabelSize + ';color:#6E7681;">VMs · ' + d.hostsOnline + ' hosts · ' + (d.hostsOnline > 0 ? Math.round(d.vmsTotal / d.hostsOnline) : '—') + '/host</span>'
        + '</div>'
        : ''),
      drillBtn(CFG.grafanaClustersUrl, 'Ver clusters')
    )

    // ── Card 3 — CPU Gauge ─────────────────────────────────────────
    var cpuColor = d.cpuWorst >= 90 ? C.crit : d.cpuWorst >= 75 ? C.warn : C.ok
    var cpuSpark = d.sparkCpu && d.sparkCpu.length >= 2 ? d.sparkCpu : []
    var c3 = card(cpuColor, 'CPU · pior host',
      gaugeSVG(d.cpuWorst, cpuColor, 160, 88, 'avg ' + _pct(d.cpuAvg))
      + (d.cpuWorstHost !== '—'
        ? '<div style="margin-top:3px;padding:4px 6px;border-radius:4px;background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.07);">'
        + '<div style="display:flex;justify-content:space-between;align-items:baseline;">'
        + '<span style="font-size:' + U.worstHostKeySize + ';color:#6E7681;letter-spacing:.06em;text-transform:uppercase;">host</span>'
        + '<span style="font-size:' + U.worstHostSize + ';color:' + cpuColor + ';font-family:monospace;">' + _esc(d.cpuWorstHost) + (d.cpuWorstVMs ? ' · <span style="color:#58A6FF;">' + d.cpuWorstVMs + ' VMs</span>' : '') + '</span>'
        + '</div>'
