      + donutSVG(tc.crit, tc.warn, tc.info, d.trigTotal, 68)
      + '<div style="flex:1;">'
      + '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;padding-bottom:5px;border-bottom:1px solid rgba(255,255,255,0.06);">'
      + '<span style="font-size:' + U.trigLabelSize + ';letter-spacing:.08em;text-transform:uppercase;color:#F85149;">CRIT</span>' + trigLink([4, 5], tc.crit, '#F85149') + '</div>'
      + '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;padding-bottom:5px;border-bottom:1px solid rgba(255,255,255,0.06);">'
      + '<span style="font-size:' + U.trigLabelSize + ';letter-spacing:.08em;text-transform:uppercase;color:#D29922;">WARN</span>' + trigLink([2, 3], tc.warn, '#D29922') + '</div>'
      + '<div style="display:flex;justify-content:space-between;align-items:center;">'
      + '<span style="font-size:' + U.trigLabelSize + ';letter-spacing:.08em;text-transform:uppercase;color:#58A6FF;">INFO</span>' + trigLink([0, 1], tc.info, '#58A6FF') + '</div>'
      + '</div>'
      + '</div>'
      // Badges de contagem
      + '<div style="display:flex;gap:4px;flex-wrap:wrap;">'
      + (d.hostsAlerta > 0 ? badge(d.hostsAlerta + ' hosts afectados', trigColor) : '')
      + (tc.crit > 0 ? badge(tc.crit + ' crit', C.crit) : '')
      + (tc.warn > 0 ? badge(tc.warn + ' warn', C.warn) : '')
      + '</div>',
