    )

    return '<div class="bpc" style="height:100%;display:flex;flex-direction:column;font-family:\'IBM Plex Sans\',\'Segoe UI\',sans-serif;">'
      + demoBar + statePill
      + '<div style="display:flex;flex:1;gap:0;overflow:hidden;">'
      + c1 + c2 + c3 + c4 + c5 + c6
      + '</div></div>'
  }

  // ── Bootstrap ─────────────────────────────────────────────────────
  window.waitForBPC(function (rpc) {
    window.BPC.utils.waitForElement(CFG.elementId, function (el) {
      function load() {
        var src = CFG.demo ? getDemoData() : getData(rpc)
        src
          .then(function (d) { el.innerHTML = render(d, !!CFG.demo, null) })
          .catch(function (e) {
            BPC.log('detail-esxi-overview v13: ' + e.message, 'error')
            getDemoData().then(function (d) { el.innerHTML = render(d, true, e.message) })
          })
      }
      load()
      window.BPC.utils.startRefresh(el, load, CFG.refreshMs)
    })
  })

}())

