    },
  }

  var _esxiHosts = null

  // ── Helpers ───────────────────────────────────────────────────────
  function _esc(s) { return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;') }
  function _pct(v) { return v == null || isNaN(v) ? '—' : v.toFixed(1) + '%' }

  function _sevLabel(p) {
    if (p >= 5) return 'DISASTER'
    if (p >= 4) return 'HIGH'
    if (p >= 3) return 'AVG'
    if (p >= 2) return 'WARN'
    if (p >= 1) return 'INFO'
    return 'OK'
  }
  function _sevColor(p) {
    if (p >= 5) return '#FF4444'
    if (p >= 4) return '#F85149'
    if (p >= 3) return '#E07B39'
    if (p >= 2) return '#D29922'
    if (p >= 1) return '#58A6FF'
    return '#3FB950'
  }
  function _metricColor(v, w, c) {
    if (v == null || isNaN(v)) return '#6E7681'
    if (v >= c) return '#F85149'
    if (v >= w) return '#D29922'
    return '#3FB950'
  }
  function _spark(data, color, w, h) {
    if (!data || data.length < 2) return ''
    var mn = Math.min.apply(null, data), mx = Math.max.apply(null, data), rng = mx - mn || 1
    var pts = data.map(function (v, i) {
      return [(i / (data.length - 1)) * w, h - ((v - mn) / rng) * (h - 2) - 1]
    })
    var ln = 'M' + pts.map(function (p) { return p[0].toFixed(1) + ',' + p[1].toFixed(1) }).join('L')
    return '<svg width="' + w + '" height="' + h + '" viewBox="0 0 ' + w + ' ' + h + '" style="display:inline-block;vertical-align:middle;opacity:.8">'
      + '<path d="' + ln + '" fill="none" stroke="' + color + '" stroke-width="1.2" stroke-linejoin="round"/>'
      + '<circle cx="' + pts[pts.length - 1][0].toFixed(1) + '" cy="' + pts[pts.length - 1][1].toFixed(1) + '" r="1.8" fill="' + color + '"/>'
      + '</svg>'
  }
  function _techName(n) {
    var m = n.match(/VIRT\s*-\s*ESXi\s*-\s*(\S+)/i)
    return m ? m[1] : n
  }
  function _uptime(raw) {
    if (!raw) return null
    var dm = raw.match(/(\d+)\s*dia/)
    if (dm && parseInt(dm[1]) > 0) return dm[1] + 'd'
    var hm = raw.match(/(\d+):/)
    if (hm && parseInt(hm[1]) > 0) return parseInt(hm[1]) + 'h'
    return '<1h'
  }
  function _sanitize(d) {
    return d.replace(/\{\$[^}]+\}/g, '').replace(/\{[A-Z_.]+\}/g, '').replace(/\s{2,}/g, ' ').trim()
  }
  function _ago(clock) {
    var s = Math.floor(Date.now() / 1000) - parseInt(clock)
    if (s < 60) return s + 's'
    if (s < 3600) return Math.floor(s / 60) + 'm'
    if (s < 86400) return Math.floor(s / 3600) + 'h'
    return Math.floor(s / 86400) + 'd'
  }
  function _gb(bytes) { return bytes > 0 ? +(bytes / 1_073_741_824).toFixed(0) : 0 }

  // Ordenação: maior priority → topo; desempate por CPU DESC
  function _weight(h) {
    if (h.noData) return -1000
    var p = h.triggers && h.triggers.length ? h.triggers[0].priority : 0
    return p * 1000 + (h.cpu || 0)
  }

  function _drillUrl(hostid) {
    if (CFG.grafanaL3) return CFG.grafanaL3 + '?var-host=' + encodeURIComponent(hostid)
    return CFG.zabbixUrl + '/zabbix.php?action=problem.view'
      + '&filter_show=1'
      + '&filter_hostids%5B%5D=' + encodeURIComponent(hostid)
      + '&filter_set=1'
  }

  // ── getESXiHosts ──────────────────────────────────────────────────
  function getESXiHosts(rpc) {
    if (_esxiHosts && _esxiHosts.length) return Promise.resolve(_esxiHosts)
    return rpc('host.get', {
      groupids: [CFG.groupId],
      selectTags: 'extend',
      output: ['hostid', 'name', 'host'],
    }).then(function (hosts) {
      _esxiHosts = hosts.filter(function (h) {
        return (h.tags || []).some(function (t) {
          return t.tag === 'activo' && t.value === 'servidores fisicos'
        })
      }).map(function (h) { return { hostid: h.hostid, name: h.name, hostName: h.host } })
      BPC.log('ESXi table: ' + _esxiHosts.length + ' hosts', 'info')
      return _esxiHosts
    })
  }

  // ── getSparklines ─────────────────────────────────────────────────
  function getSparklines(rpc, cpuByHost) {
    var ids = Object.keys(cpuByHost).map(function (hid) { return cpuByHost[hid] }).filter(Boolean)
    if (!ids.length) return Promise.resolve({})
    var timeFrom = Math.floor(Date.now() / 1000) - CFG.sparkSeconds
    return rpc('history.get', {
      itemids: ids, history: 0, time_from: timeFrom,
      output: 'extend', sortfield: 'clock', sortorder: 'ASC', limit: 5000,
    }).then(function (rows) {
      if (!Array.isArray(rows)) return {}
      var i2h = {}
      Object.keys(cpuByHost).forEach(function (hid) { i2h[cpuByHost[hid]] = hid })
      var bh = {}
      rows.forEach(function (r) {
        var hid = i2h[r.itemid]; if (!hid) return
        var b = Math.floor(parseInt(r.clock) / 60) * 60
        if (!bh[hid]) bh[hid] = {}
        if (!bh[hid][b]) bh[hid][b] = []
        bh[hid][b].push(parseFloat(r.value))
      })
      var res = {}
      Object.keys(bh).forEach(function (hid) {
        res[hid] = Object.keys(bh[hid]).sort().map(function (t) {
          var v = bh[hid][t]; return v.reduce(function (s, x) { return s + x }, 0) / v.length
        })
      })
      return res
    }).catch(function () { return {} })
  }

  // ── getData ───────────────────────────────────────────────────────
