        items.forEach(function (i) {
          if (!metricsByHost[i.hostid]) metricsByHost[i.hostid] = { _ds: {} }

          if (i.name.indexOf('Free space on datastore [') !== -1) {
            var m = i.name.match(/\[([^\]]+)\]/); if (!m) return
            var nm = m[1], fp = parseFloat(i.lastvalue); if (isNaN(fp)) return
