      + thead + tbody + '</table>'

    return '<div class="bpc" style="height:100%;display:flex;flex-direction:column;font-family:' + S.fontFamily + ';overflow:hidden;">'
      + demoBar + summary
      + '<div style="flex:1;overflow:auto;">'
      + table
      + '</div></div>'
  }

  // ── Bootstrap ─────────────────────────────────────────────────────
  window.waitForBPC(function (rpc) {
    window.BPC.utils.waitForElement(CFG.elementId, function (el) {
      function load() {
        var src = CFG.demo ? getDemoData() : getData(rpc)
        src
          .then(function (hosts) { el.innerHTML = render(hosts, !!CFG.demo, null) })
          .catch(function (e) {
            BPC.log('detail-esxi-table: ' + e.message, 'error')
            getDemoData().then(function (hosts) { el.innerHTML = render(hosts, true, e.message) })
