    var timeFrom = Math.floor(Date.now() / 1000) - CFG.sparkSeconds
    return rpc('history.get', {
      itemids: ids, history: 0, time_from: timeFrom,
      output: 'extend', sortfield: 'clock', sortorder: 'ASC', limit: 5000,
    }).then(function (rows) {
      if (!Array.isArray(rows)) return {}
      var i2h = {}
      Object.keys(cpuByHost).forEach(function (hid) { i2h[cpuByHost[hid]] = hid })
      var bh = {}
      rows.forEach(function (r) {
        var hid = i2h[r.itemid]; if (!hid) return
        var b = Math.floor(parseInt(r.clock) / 60) * 60
        if (!bh[hid]) bh[hid] = {}
        if (!bh[hid][b]) bh[hid][b] = []
        bh[hid][b].push(parseFloat(r.value))
      })
      var res = {}
      Object.keys(bh).forEach(function (hid) {
        res[hid] = Object.keys(bh[hid]).sort().map(function (t) {
          var v = bh[hid][t]; return v.reduce(function (s, x) { return s + x }, 0) / v.length
        })
      })
      return res
    }).catch(function () { return {} })
  }

  // ── getData ───────────────────────────────────────────────────────
  function getData(rpc) {
    return getESXiHosts(rpc).then(function (esxiHosts) {
      if (!esxiHosts.length) throw new Error('Nenhum host ESXi com tag esperada')
      var hostIds = esxiHosts.map(function (h) { return h.hostid })

      return Promise.all([
        rpc('item.get', {
          hostids: hostIds,
          search: {
            name: [
              'CPU usage in percent', 'Used memory', 'Total memory',
              'Number of guest VMs', 'Cluster name', 'Uptime',
              'Power usage', 'Connection state',
              'Free space on datastore [', 'Total size of datastore [',
            ]
          },
          searchByAny: true,
          output: ['hostid', 'name', 'lastvalue', 'itemid'],
          monitored: true, limit: 5000,
        }),
        rpc('trigger.get', {
          hostids: hostIds,
          only_true: true, monitored: true, skipDependent: true,
          expandDescription: true,
          output: ['triggerid', 'description', 'priority', 'lastchange', 'value'],
          selectHosts: ['hostid'],
          sortfield: 'priority', sortorder: 'DESC', limit: 500,
        }),
      ]).then(function (results) {
        var items = results[0]
        var triggers = results[1].filter(function (t) { return String(t.value) === '1' })

        var metricsByHost = {}, cpuByHost = {}
        var dsDataByName = {}   // dsName → { free, total }

        items.forEach(function (i) {
          if (!metricsByHost[i.hostid]) metricsByHost[i.hostid] = { _ds: {} }

          if (i.name.indexOf('Free space on datastore [') !== -1) {
            var m = i.name.match(/\[([^\]]+)\]/); if (!m) return
            var nm = m[1], fp = parseFloat(i.lastvalue); if (isNaN(fp)) return
            if (!dsDataByName[nm]) dsDataByName[nm] = { free: fp, total: 0 }
            else if (fp < dsDataByName[nm].free) dsDataByName[nm].free = fp
            return
          }
          if (i.name.indexOf('Total size of datastore [') !== -1) {
            var m2 = i.name.match(/\[([^\]]+)\]/); if (!m2) return
            var nm2 = m2[1], tot = parseFloat(i.lastvalue); if (isNaN(tot)) return
            if (!dsDataByName[nm2]) dsDataByName[nm2] = { free: 100, total: tot }
            else dsDataByName[nm2].total = tot
            return
          }

          metricsByHost[i.hostid][i.name] = i.lastvalue
          if (i.name === 'CPU usage in percent') cpuByHost[i.hostid] = i.itemid
        })

        // DS globais ordenados por livre ASC
        var dsGlobal = Object.keys(dsDataByName).map(function (n) {
          var d = dsDataByName[n]
          var totalGb = _gb(d.total)
          var usedGb = totalGb > 0 ? Math.round(totalGb * (1 - d.free / 100)) : 0
          return { dsName: n, freePct: d.free, totalGb: totalGb, usedGb: usedGb }
        }).sort(function (a, b) { return a.freePct - b.freePct })

        // Triggers por host — até 3
        var trigsByHost = {}
        triggers.forEach(function (t) {
          var desc = _sanitize(t.description)
            ; (t.hosts || []).forEach(function (h) {
              if (!trigsByHost[h.hostid]) trigsByHost[h.hostid] = []
              if (trigsByHost[h.hostid].length < 3) {
                trigsByHost[h.hostid].push({
                  description: desc,
                  priority: parseInt(t.priority),
                  lastchange: t.lastchange,
                })
              }
            })
        })

        return getSparklines(rpc, cpuByHost).then(function (sparks) {
          return esxiHosts.map(function (esxi) {
            var m = metricsByHost[esxi.hostid] || {}
            var cpu = parseFloat(m['CPU usage in percent'])
            var ramU = parseFloat(m['Used memory'])
            var ramT = parseFloat(m['Total memory'])
            var ram = ramT > 0 ? (ramU / ramT) * 100 : NaN
            var noData = isNaN(cpu)
            var hostTrigs = trigsByHost[esxi.hostid] || []
            var top = hostTrigs[0] || null

            var techName = _techName(esxi.hostName)
            // visible name: se diferente do techName, usar esxi.name
            var visName = (esxi.name && esxi.name !== esxi.hostName && esxi.name !== techName)
              ? esxi.name : null

            return {
              hostid: esxi.hostid,
              techName: techName,
              visName: visName,
              fullName: esxi.hostName,
              noData: noData,
              cpu: noData ? null : +cpu.toFixed(1),
              ram: noData ? null : +ram.toFixed(1),
              cpuColor: _metricColor(cpu, 75, 90),
              ramColor: _metricColor(ram, 70, 85),
              ramUsedGb: noData ? null : _gb(ramU),
              ramTotGb: noData ? null : _gb(ramT),
              vms: parseInt(m['Number of guest VMs']) || 0,
              cluster: m['Cluster name'] || '—',
              uptime: _uptime(m['Uptime'] || ''),
              power: (function () { var p = parseFloat(m['Power usage']); return isNaN(p) ? null : Math.round(p) + ' W' })(),
              connected: (function () { var c = (m['Connection state'] || '').toLowerCase(); return c.indexOf('connected') !== -1 && c.indexOf('disconnected') === -1 })(),
              triggers: hostTrigs,
              topTrigger: top,
              // DS globais — mesmos para todos (partilhados)
              dsWorst: dsGlobal.slice(0, 3),
              sparkCpu: sparks[esxi.hostid] || [],
            }
          })
        })
      })
    })
  }

