        + '<div style="display:flex;align-items:center;gap:4px;flex-shrink:0;margin-top:2px;">'
        + '<span style="font-size:8px;color:#6E7681;white-space:nowrap;max-width:65px;overflow:hidden;text-overflow:ellipsis;" title="' + _esc(h.cluster) + '">' + _esc(h.cluster) + '</span>'
        + '<span style="font-size:8px;font-weight:700;letter-spacing:.06em;padding:1px 5px;border-radius:3px;background:rgba(0,0,0,0.25);color:' + topColor + ';border:1px solid ' + topColor + '44;white-space:nowrap;">' + pillLabel + '</span>'
        + '</div>'
        + '</div>'

        // CPU
        + '<div style="display:flex;justify-content:space-between;align-items:center;">'
        + '<span style="font-size:9px;color:#6E7681;letter-spacing:.06em;width:28px;">CPU</span>'
        + '<div style="flex:1;display:flex;align-items:center;justify-content:flex-end;gap:6px;">'
        + (h.sparkCpu && h.sparkCpu.length >= 2 ? _spark(h.sparkCpu, h.cpuColor, 52, 14) : '')
        + '<span style="font-size:11px;font-weight:700;color:' + h.cpuColor + ';min-width:38px;text-align:right;">' + _pct(h.cpu) + '</span>'
        + '</div>'
        + '</div>'
        + _bar(h.cpu, h.cpuColor)

        // RAM
        + '<div style="display:flex;justify-content:space-between;align-items:center;margin-top:4px;">'
        + '<span style="font-size:9px;color:#6E7681;letter-spacing:.06em;width:28px;">RAM</span>'
        + '<div style="display:flex;align-items:center;gap:5px;">'
        + '<span style="font-size:9px;color:#404852;">' + h.ramUsedGb + '/' + h.ramTotGb + ' GB</span>'
        + '<span style="font-size:11px;font-weight:700;color:' + h.ramColor + ';min-width:38px;text-align:right;">' + _pct(h.ram) + '</span>'
        + '</div>'
        + '</div>'
        + _bar(h.ram, h.ramColor)

        + footerHtml
        + trigsHtml
        + dsHtml
        + '</div>'
    }).join('')

    return '<div class="bpc" style="height:100%;display:flex;flex-direction:column;font-family:\'IBM Plex Sans\',\'Segoe UI\',sans-serif;overflow:hidden;">'
      + demoBar + summary
      + '<div style="flex:1;overflow-y:auto;padding:8px 10px;">'
      + '<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:7px;">'
      + cards + '</div></div></div>'
  }

  // ── Bootstrap ─────────────────────────────────────────────────────
  window.waitForBPC(function (rpc) {
    window.BPC.utils.waitForElement(CFG.elementId, function (el) {
      function load() {
        var src = CFG.demo ? getDemoData() : getData(rpc)
        src
          .then(function (hosts) { el.innerHTML = render(hosts, !!CFG.demo, null) })
          .catch(function (e) {
            BPC.log('detail-esxi-grid v6: ' + e.message, 'error')
            getDemoData().then(function (hosts) { el.innerHTML = render(hosts, true, e.message) })
          })
      }
      load()
      window.BPC.utils.startRefresh(el, load, CFG.refreshMs)
    })
  })

}())
